extern char ekernel[];

#define ALL_USED 0xffu

int last_free_page;

uint8 mbitmaps[PGNUM / (PGSIZE * 8)][PGSIZE];

void freerange(void *pa_start, void *pa_end)
{
	uint64 s_off = PGROUNDUP((uint64)pa_start) - PHYSTART;
	uint64 e_off = PGROUNDDOWN((uint64)pa_end) - PHYSTART;

	int s_page_no = s_off / PGSIZE;
	int e_page_no = e_off / PGSIZE;
	// infof(" [freerange] s_page_no: %d, e_page_no: %d", s_page_no, e_page_no);
	if(s_page_no < last_free_page){
		last_free_page = s_page_no;
	}

	int s_i = s_page_no / (PGSIZE * 8);
	int s_j = (s_page_no % (PGSIZE * 8)) / 8;
	int k = (s_page_no % (PGSIZE * 8)) % 8;
	// infof(" [freerange] s_i: %d, s_j: %d, k: %d", s_i, s_j, k);
	while(k < 8){
		mbitmaps[s_i][s_j] &= ~(1 << k);
		// infof(" [freerange] mbitmaps[%d][%d] = %2x, s_page_no: %d", s_i, s_j, mbitmaps[s_i][s_j], s_page_no);
		k++;
		s_page_no++;
	}
	s_i = s_page_no / (PGSIZE * 8);
	s_j = (s_page_no % (PGSIZE * 8)) / 8;

	int e_i = e_page_no / (PGSIZE * 8);
	int e_j = (e_page_no % (PGSIZE * 8)) / 8;
	k = (e_page_no % (PGSIZE * 8)) % 8;
	// infof(" [freerange] e_i: %d, e_j: %d, k: %d", e_i, e_j, k);
	while(k >= 0){
		mbitmaps[e_i][e_j] &= ~(1 << k);
		k--;
		e_page_no--;
	}

	int diff = e_page_no - s_page_no + 1;
	if(diff % 8){
		panic("algorithm error");
	}

	memset(&mbitmaps[s_i][s_j], 0, diff / 8);
}

void kinit()
{
	last_free_page = PGNUM;
	// infof(" [kinit] mbitmaps size: %d", sizeof(mbitmaps));
	memset(mbitmaps, 0xff, sizeof(mbitmaps));
	// printbuf(mbitmaps, sizeof(mbitmaps), 64);
	// infof(" [kinit] start freerange");
	freerange(ekernel, (void *)PHYSTOP);
	// infof(" [kinit] end freerange");
	// printbuf(mbitmaps, sizeof(mbitmaps), 64);
	// panic("000");
}

// Free the page of physical memory pointed at by v,
// which normally should have been returned by a
// call to kalloc().  (The exception is when
// initializing the allocator; see kinit above.)
void kfree(void *pa)
{
	// struct linklist *l;
	if (((uint64)pa % PGSIZE) != 0 || (char *)pa < ekernel ||
	    (uint64)pa >= PHYSTOP)
		panic("kfree:ek: %p, %p", ekernel, pa);
	// Fill with junk to catch dangling refs.
	memset(pa, 1, PGSIZE);
	uint64 off = (uint64)pa - PHYSTART;
	int page_no = off / PGSIZE;
	if(page_no < last_free_page){
		last_free_page = page_no;
	}
	int i = page_no / (PGSIZE * 8);
	int j = (page_no % (PGSIZE * 8)) / 8;
	int k = (page_no % (PGSIZE * 8)) % 8;
	// infof(" [kfree] page_no: %d, i: %d, j: %d, k: %d", page_no, i, j, k);
	mbitmaps[i][j] &= ~(1 << k);
}

// Allocate one 4096-byte page of physical memory.
// Returns a pointer that the kernel can use.
// Returns 0 if the memory cannot be allocated.
void *kalloc()
{
	int i = last_free_page / (PGSIZE * 8);
	int j = (last_free_page % (PGSIZE * 8)) / 8;
	for(; i < PGNUM / (PGSIZE * 8); i++){
		for(j = (j == PGSIZE ? j : 0); j < PGSIZE; j++){
			// infof(" [kalloc] mbitmaps[%d][%d] = %x", i, j, mbitmaps[i][j]);
			if(mbitmaps[i][j] != ALL_USED){
				for(int k = 0; k < 8; k++){
					// infof(" [kalloc] bits: %d", mbitmaps[i][j] & (1 << k));
					if(!(mbitmaps[i][j] & (1 << k))){
						// infof(" [kalloc] i: %d, j: %d, k:%d", i, j, k);
						mbitmaps[i][j] |= 1 << k;
						return (void *)(((i * PGSIZE + j * 8) + k) * PGSIZE + PHYSTART);
					}
				}
			}
		}
	}
	return (void *)0;
}

void *kalloc_n(int n){
	panic("not achieved function! :%d", n);
	if(n <= 0){
		errorf("page num error");
		return 0;
	}
	int pg_num;
	if(n <= 8){
		pg_num = 8;
	}else if(n <= 16){
		pg_num = 16;
	}else if(n <= 32){
		pg_num = 32;
	}else if(n <= 64){
		pg_num = 64;
	}else{
		panic("page num exceed the limit");
	}

	switch(pg_num){
	case 8:

	case 16:

	case 32:

	case 64:
		break;
	}

}

void kfree_n(void *ptr, int n){
	panic("not achieved function!");
}

uint64 get_free_pages_num(){
	uint64 cnt = 0;
	for(uint64 i = 0; i <PGNUM / (PGSIZE * 8); i++){
		for(int j = 0; j < PGSIZE; j++){
			uint8 byte = mbitmaps[i][j];
			if(byte== ALL_USED){
				continue;
			}else if(byte == ~ALL_USED){
				cnt += 8;
				continue;
			}
			for(int k = 0; k < 8; k++){
				if(!(byte << k)){
					cnt++;
				}
			}
		}
	}
	return cnt;
}

#include <mm/malloc.h>
#include <mm/vm.h>
