#define MAX_MALLOC_ENTRY_PAGE_NUM 256
#define MALLOC_ENTRY_SIZE 16
#define MALLOC_ENTRY_NUM_PER_PAGE (PGSIZE / MALLOC_ENTRY_SIZE)

struct malloc_entry{
    void *ptr;
    size_t size;
};

struct bin_ctl{
    uint64 sz256;
    uint32 sz512;
    uint16 sz1024;
}bin_bitmaps;

uint64 malloc_entry_pages[MAX_MALLOC_ENTRY_PAGE_NUM];

int malloc_entry_num;

uint64 bin_pages[3][4];//256,512,1024,4096

struct malloc_entry *find_malloc_entry(void *ptr){
    struct malloc_entry *p;
    for(int i = 0; i < malloc_entry_num; i++){
        p = malloc_entry_pages[i / MALLOC_ENTRY_NUM_PER_PAGE] + i % MALLOC_ENTRY_NUM_PER_PAGE * MALLOC_ENTRY_SIZE;
        if(p->ptr == ptr){
            return p;
        }
    }
    return NULL;
}

static inline struct malloc_entry *find_malloc_entry_from_no(int no){
    return malloc_entry_pages[no / MALLOC_ENTRY_NUM_PER_PAGE] + no % MALLOC_ENTRY_NUM_PER_PAGE * MALLOC_ENTRY_SIZE;
}

void add_malloc_entry(void *ptr, size_t size){
    if(malloc_entry_num % MALLOC_ENTRY_NUM_PER_PAGE == 0
        && malloc_entry_pages[malloc_entry_num / MALLOC_ENTRY_NUM_PER_PAGE] == 0){
            uint64 addr = malloc_entry_pages[malloc_entry_num / MALLOC_ENTRY_NUM_PER_PAGE] = kalloc();
            // infof(" [%s] addr: %p", __func__, addr);
        }
    struct malloc_entry *p = find_malloc_entry_from_no(malloc_entry_num);
    p->ptr = ptr;
    p->size = size;
    malloc_entry_num++; 
}

void malloc_init(){
    memset(malloc_entry_pages, 0, sizeof(malloc_entry_pages));
    uint64 addr = malloc_entry_pages[0] = kalloc();
    // kvmmap(kernel_pagetable, addr, addr, PGSIZE, PTE_R | PTE_W);
    // infof(" [%s] addr: %p", __func__, addr);
    memset(malloc_entry_pages[0], 0, PGSIZE);
    malloc_entry_num = 0;
    for(int i =0; i < 3; i++){
        for(int j = 0; j < 4; j++){
            addr = bin_pages[i][j] = kalloc();
            // kvmmap(kernel_pagetable, addr, addr, PGSIZE, PTE_R | PTE_W);
            // infof(" [%s] addr: %p", __func__, addr);
        }
    }
    memset(&bin_bitmaps, 0, sizeof(bin_bitmaps));
}

void *malloc(size_t size){
    // printf("%s(size: %d)\n", __func__, size);
    void *p;
    size_t nsize;
    if(size <= 256){
        // infof(" [%s] case256", __func__);
        if(bin_bitmaps.sz256 == 0xffffffffffffffff){
            // infof("bins256 is full!");
            goto case512;
        }
        nsize = 256;
        // errorf(" [%s] bitmaps.sz256: %p", __func__, bin_bitmaps.sz256);
        for(int i = 0; i < 64; i++){
            if((bin_bitmaps.sz256 & (1 << i)) == 0){
                // infof(" [%s] i: %d", __func__, i);
                bin_bitmaps.sz256 |= (1 << i);
                p = bin_pages[0][i / 16] + (i % 16) * 256;
                break;
            }
        }
    }else if(size <= 512){
        case512:
        if(bin_bitmaps.sz512 == 0xffffffff){
            // infof("bins512 is full!");
            goto case1024;
        }
        nsize = 512;
        for(int i = 0; i < 32; i++){
            if((bin_bitmaps.sz512 & (1 << i)) == 0){
                bin_bitmaps.sz512 |= 1 << i;
                p = bin_pages[1][i / 8] + (i % 8) * 512;
                break;
            }
        }
    }else if(size <= 1024){
        case1024:
        if(bin_bitmaps.sz1024 == 0xffff){
            // infof("bins1024 is full!");
            goto case4096;
        }
        nsize = 1024;
        for(int i = 0; i < 16; i++){
            if((bin_bitmaps.sz1024 & (1 << i)) == 0){
                bin_bitmaps.sz1024 |= 1 << i;
                p = bin_pages[2][i / 4] + (i % 4) * 1024;
                break;
            }
        }
    }else if(size <= 4096){
        case4096:
        nsize = 4096;
        p = kalloc();
        // kvmmap(kernel_pagetable, p, p, PGSIZE, PTE_R | PTE_W);
        // infof(" [%s] addr: %p", __func__, p);
    }else{
        nsize = PGROUNDUP(size);
        p = kalloc_n(nsize / PGSIZE);
    }
    add_malloc_entry(p, nsize);
    // warnf("%p --- %p", p, p + nsize);
    return p;
}

void *calloc(size_t nitems, size_t size){
    // errorf("%s(size: %d)", __func__, nitems * size);
    void *p = malloc(nitems * size);
    memset(p, 0, size);
    return p;
}

void *realloc(void *ptr, size_t size){
    // infof("%s", __func__);
    void *p = malloc(size);
    size_t osize = find_malloc_entry(ptr)->size;
    memmove(p, ptr, osize);
    free(ptr);
    return p;
}

void free(void * ptr){
    // infof("%s(ptr: %p)", __func__, ptr);
    if(!ptr){
        errorf("try to free a nullptr!");
        return;
    }
    struct malloc_entry* p = find_malloc_entry(ptr);
    if(!p){
        errorf("not an allocated ptr!");
    }
    switch(p->size){
    case 256:
        for(int i = 0; i < 4; i++){
            if(bin_pages[0][i] == PGROUNDDOWN((uint64)p->ptr)){
                for(int j = 0; j < 16; j++){
                    if(bin_pages[0][i] + j * 256 == p->ptr){
                        bin_bitmaps.sz256 &= ~(1 << (i * 16 + j));
                        goto small;
                    }
                }
            }
        }
        break;
    case 512:
        for(int i = 0; i < 4; i++){
            if(bin_pages[1][i] == PGROUNDDOWN((uint64)p->ptr)){
                for(int j = 0; j < 8; j++){
                    if(bin_pages[1][i] + j * 512 == p->ptr){
                        bin_bitmaps.sz512 &= ~(1 << (i * 8 + j));
                        goto small;
                    }
                }
            }
        }
        break;
    case 1024:
        for(int i = 0; i < 4; i++){
            if(bin_pages[2][i] == PGROUNDDOWN((uint64)p->ptr)){
                for(int j = 0; j < 4; j++){
                    if(bin_pages[2][i] + j * 1024 == p->ptr){
                        bin_bitmaps.sz1024 &= ~(1 << (i * 4 + j));
                        goto small;
                    }
                }
            }
        }
        break;
    case 4096:
        kfree(p->ptr);
        goto free_end;
        break;
    default:
        kfree_n(p->ptr, p->size / PGSIZE);
        goto free_end;
        break;
    }
    small:
    //fill memory with junks
    memset(ptr, 1, p->size);

    free_end:
    memmove(p, find_malloc_entry_from_no(malloc_entry_num - 1), MALLOC_ENTRY_SIZE);
    malloc_entry_num--;
}

