pagetable_t kernel_pagetable;

extern char e_text[]; // kernel.ld sets this to end of kernel code.
extern char trampoline[];

// Make a direct-map page table for the kernel.
pagetable_t kvmmake()
{
	pagetable_t kpgtbl = 0;
	kpgtbl = (pagetable_t)kalloc();
	infof("kalloc success");
	memset(kpgtbl, 0, PGSIZE);
	// uart registers
	kvmmap(kpgtbl, UART_V, UART, PGSIZE, PTE_R | PTE_W);
	infof("uart");
	#ifdef QEMU
	// virtio mmio disk interface
	kvmmap(kpgtbl, VIRTIO0, VIRTIO0, PGSIZE, PTE_R | PTE_W);
	infof("virt disk");
	#else
	kvmmap(kpgtbl, SD_BASE_V, SD_BASE, 0x10000, PTE_R | PTE_W);
	infof("sdcard");
	#endif
	// CLINT
	kvmmap(kpgtbl, CLINT_V, CLINT, 0x10000, PTE_R | PTE_W);
	infof("clint");
	// PLIC
	kvmmap(kpgtbl, PLIC_V, PLIC, 0x4000, PTE_R | PTE_W);
	kvmmap(kpgtbl, PLIC_V + 0x200000, PLIC + 0x200000, 0x4000, PTE_R | PTE_W);
	infof("plic");

	infof("map devs success");
	// map kernel text executable and read-only.
	kvmmap(kpgtbl, KERNBASE_V, KERNBASE, (uint64)e_text - KERNBASE,
	       PTE_R | PTE_X);
	infof("map kernel success");
	// map kernel data and the physical RAM we'll make use of.
	kvmmap(kpgtbl, (uint64)e_text, (uint64)e_text, PHYSTOP - (uint64)e_text,
	       PTE_R | PTE_W);
	infof("map memory success");
	kvmmap(kpgtbl, TRAMPOLINE, (uint64)trampoline, PGSIZE, PTE_R | PTE_X);
	infof("map trampoline success");
	return kpgtbl;
}

// Initialize the one kernel_pagetable
// Switch h/w page table register to the kernel's page table,
// and enable paging.
