// Scheduler never returns.  It loops, doing:
//  - choose a process to run.
//  - swtch to start running that process.
//  - eventually that process transfers control
//    via swtch back to the scheduler.
void scheduler()
{
	struct thread *t;
	for (;;) {
		t = fetch_task();
		if (t == NULL) {
			panic("all app are over!\n");
		}
		if(t->state == SLEEPING && t->wake_time != 0){
			if(get_cycle() >= t->wake_time){
				t->state = RUNNABLE;
			}
			else add_task(t);
		}
		// throw out freed threads
		if (t->state != RUNNABLE) {
			// warnf("not RUNNABLE", t->process->pid, t->tid);
			continue;
		}

		struct proc *p = curr_proc();
		p->tms_u_start = get_cycle();
		p->tms_s_start = 0;
		// infof("ra: %p", t->context.ra);
		t->state = RUNNING;
		current_thread = t;
		// infof("swtich(%p) to proc %d, thread %d", swtch, t->process->pid, t->tid);
		swtch(&idle.context, &t->context);
	}
}

