		f = fileopen(p->cwd, path, flags);
	}else{
		if(fd < 0){
			return -1;
		}
		f = p->files[fd];
		if(!f->isdir){
			return -1;
		}
		f = fileopen(f->path , path, flags);
	}
	free(path);
	if(!f){
		return -1;
	}
	int nfd = fdalloc(f);
	if(nfd){
		return nfd;
	}
	fileclose(f);
	return -1;
}

int sys_close(int fd)
{
	// printf("sys_close -- fd: %d\n", fd);
	if (fd < 0 || fd > FD_BUFFER_SIZE)
		return -1;
	struct proc *p = curr_proc();
	struct file *f = p->files[fd];
	if (f == NULL) {
		errorf("invalid fd %d", fd);
		return -1;
	}
	fileclose(f);
	p->files[fd] = 0;
	return 0;
}

