/**
 * @brief 获取挂载点索引
 * @param path 待解析路径
 * @param is_target 若为0则根据挂载点目标进行匹配,否则根据源路径进行匹配
 * @param len 返回最大匹配长度
 * @param idx 返回挂载点索引
 * @return 找到挂载点返回0,否则返回-1
 */
static int get_mp_idx(const char *path, int is_target, int *len, int *idx){
    if(!path || path[0] == 0){
        errorf("path cannot be null");
        return -1;
    }
    for(int i = strlen(path) - 1; i >= 0; i--){
        for(int j = 0; j < MAX_MOUNT_POINT_NUM; j++){
            if(is_target){
                if(mps[j].mounted && strlen(mps[j].target) == i + 1 && !strncmp(mps[j].target, path, i + 1)){
                    if(len){
                        *len = i;
                    }
                    if(idx){
                        *idx = j;
                    }
                    return 0;
                }
            }else{
                if(mps[j].mounted && strlen(mps[j].source) == i + 1 && !strncmp(mps[j].source, path, i + 1)){
                    if(len){
                        *len = i;
                    }
                    if(idx){
                        *idx = j;
                    }
                    return 0;
                }
            }
        }
    }
    return -1;
}

