//The operation performed on the system-level open file table entry after some process closes a file.
void fileclose(struct file *f)
{
	if (f->ref < 1)
		panic("fileclose");
	if (--f->ref > 0) {
		return;
	}
	switch (f->type) {
	case FD_STDIO:
		// Do nothing
		break;
	case FD_PIPE:
		pipeclose(f->pipe, f->writable);
		break;
	case FD_INODE:
		// printf("file close -- inode num: %d\n", f->ip->inum);
		// iput_fat32(f->ip);
		fs_file_close(f);
		break;
	default:
		panic("unknown file type %d\n", f->type);
	}

	f->off = 0;
	f->readable = 0;
	f->writable = 0;
	f->ref = 0;
	f->type = FD_NONE;
	f->isdir = 0;
	f->filesys = FS_UNKNOWN;
}

