static char *gen_short_name(uint16 *name, uint8 len){
    //获取拓展名
    int ext_start;
    int have_ext = 0;
    for(ext_start = len - 1; ext_start >= 0 && ext_start >= len - 4; ext_start --){
        if(ext_start && name[ext_start] == '.'){
            have_ext = 1;
            break;
        }
    }
    static char str[11];
    memset(str, ' ', 11);
    if(have_ext){
        for(int i = ext_start + 1; i < len; i ++){
            str[i] = (char)(0x7F & name[i]);
        }
    }else{
        ext_start = len;
    }
    if(ext_start > 8){
        for(int i = 0; i < 2; i++){
            if(name[i] >= 'a' && name[i] <= 'z'){
                str[i] = (char)name[i] - 'a' + 'A';
            }else{
                str[i] = (char)(0x7F & name[i]);
            }
        }
        uint16 sum = 0;
        for(int i = 0; i < len; i ++){
            sum += name[i];
        }
        for(int i = 0; i < 6; i++){
            str[i + 2] = (char)(sum % (i + 5) + '0');
        }
    }else{
        for(int i = 0; i < ext_start; i++){
            if(name[i] >= 'a' && name[i] <= 'z'){
                str[i] = (char)name[i] - 'a' + 'A';
            }else{
                str[i] = (char)(0x7F & name[i]);
            }
        }
    }
    return str;
}

