		pi->writeopen = 0;
	} else {
		pi->readopen = 0;
	}
	if (pi->readopen == 0 && pi->writeopen == 0) {
		kfree((char *)pi);
	}
}

int pipewrite(pagetable_t pg, struct pipe *pi, uint64 addr, int n)
{
	// panic("%s", __func__);
	int w = 0;
	uint64 size;
	if (n <= 0) {
		panic("invalid read num");
	}
	while (w < n) {
		if (pi->readopen == 0) {
			return -1;
		}
		if (pi->nwrite == pi->nread + PIPESIZE) { // DOC: pipewrite-full
			yield();
		} else {
			size = MIN(MIN(n - w,
				       pi->nread + PIPESIZE - pi->nwrite),
				   PIPESIZE - (pi->nwrite % PIPESIZE));
			if(pg){
				if (copyin(pg,
				   &pi->data[pi->nwrite % PIPESIZE], addr + w,
				   	size) < 0) {
					panic("copyin");
				}
			}else{
				memmove(&pi->data[pi->nwrite % PIPESIZE], addr + w, size);
			}
			pi->nwrite += size;
			w += size;
		}
	}
	return w;
}

int piperead(pagetable_t pg, struct pipe *pi, uint64 addr, int n)
{
	// panic("%s", __func__);
	int r = 0;
	uint64 size = -1;
	if (n <= 0) {
		panic("invalid read num");
	}
	while (pi->nread == pi->nwrite) {
		if (pi->writeopen)
			yield();
		else
			return -1;
	}
	while (r < n && size != 0) { // DOC: piperead-copy
		if (pi->nread == pi->nwrite)
			break;
		size = MIN(MIN(n - r, pi->nwrite - pi->nread),
			   PIPESIZE - (pi->nread % PIPESIZE));
		if(pg){
			if (copyout(pg, addr + r,
			    	&pi->data[pi->nread % PIPESIZE], size) < 0) {
				panic("copyout");
			}
		}else{

			memmove(addr + r, &pi->data[pi->nread % PIPESIZE], size);
		}
		pi->nread += size;
		r += size;
	}
	return r;
}

