timer timers[NTIMERS];
uint ticks;
int hastimer = 0;

/// read the `mtime` regiser
uint64 get_cycle()
{
	return r_time();
}

/// Enable timer interrupt
void timer_init()
{
	// Enable supervisor timer interrupt
	w_sie(r_sie() | SIE_STIE);
	set_next_timer();
}

/// Set the next timer interrupt
void set_next_timer()
{
	const uint64 timebase = CPU_FREQ / TICKS_PER_SEC;
	set_timer(get_cycle() + timebase);
}

uint64 setitimer(int which, const struct itimerval *value, struct itimerval *ovalue) {
  int pid = curr_proc()->pid;
  struct timer *timer = NULL;
  for (int i = 0; i < NTIMERS; i++) {
    if (timers[i].pid == pid && timers[i].which == which) {
      timer = &timers[i];
      break;
    }
  }
  if (ovalue != NULL && timer != NULL) {
    copyout(curr_proc()->pagetable, (uint64)ovalue, (char *)&((timer->itimer)),
            sizeof(struct itimerval));
  }

  if (value != NULL) {
    if (value->it_value.sec == 0 && value->it_value.usec == 0 &&
        value->it_interval.sec == 0 && value->it_interval.usec == 0) {
      return 0;
    }
    if (timer == NULL) {
      for (int i = 0; i < NTIMERS; i++) {
        if (timers[i].pid == 0) {
          // printf("set timer pid %d\n", pid);
          timer = &timers[i];
          timer->pid = pid;
          timer->which = which;
          timer->ticks = ticks;
          break;
        }
      }
    } else {
      timer->itimer = *value;
      timer->which = which;
      timer->ticks = ticks;
      timer->pid = pid;
    }
    hastimer = 1;
  }
  return 0;
}

