#include <mm/kalloc.h>

fdt_header *fdt_hdr;
fdt_reserve_entry *fdt_mem_rsv;
uint32 *fdt_structs;
void *fdt_structs_end;
char *fdt_strings;
void *fdt_end;

fdt_property *fdt_property_pool[FDT_PROPERTY_PAGE_NUM];
int next_property;

fdt_node *fdt_node_pool[FDT_NODE_PAGE_NUM];
int next_node;

fdt_node *fdt_root_node;

static void ident(int level){
    while((level--) > 0){
        printf("  ");
    }
}

static fdt_property *alloc_property(){
    if(next_property < FDT_PROPERTY_NUM){
         int i = next_property / FDT_PROPERTY_PER_PAGE;
         int j = next_property % FDT_PROPERTY_PER_PAGE;
         next_property++;
         return &fdt_property_pool[i][j];
    }
    errorf("no free fdt property");
    return 0;
}

static fdt_node *alloc_node(){
    if(next_node < FDT_NODE_NUM){
        int i = next_node / FDT_NODE_PER_PAGE;
        int j = next_node % FDT_NODE_PER_PAGE;
        next_node++;
        return &fdt_node_pool[i][j];
    }
    errorf("no free fdt node");
    return 0;
}

static void add_sub_node(fdt_node *parent, fdt_node *sub){
    sub->parent = parent;
    fdt_node *p = parent->sub;
    if(p){
        while(p->next){
            p = p->next;
        }
        p->next = sub;
    }else{
        parent->sub = sub;
    }
}

static void add_property(fdt_node *node, fdt_property *property){
    fdt_property *p = node->property;
    if(p){
        while(p->next){
            p = p->next;
        }
        p->next = property;
    }else{
        node->property = property;
    }
}

static void fdt_structs_travel(){
    // fdt_print();
    uint32 *t = fdt_structs;
    infof("start travel at: %p", t);
    fdt_node **travel_stack = kalloc();
    int stack_top = 0;
    // printf("stack top: %d\n", stack_top);
    while(t < fdt_structs_end){
        // printf("*t: %d\n", bltrans_32(*t));
        switch (bltrans_32(*t)){
        case FDT_BEGIN_NODE:
            // printf("node_begin: %d\n", stack_top);
            t++;
            travel_stack[stack_top] = alloc_node();
            travel_stack[stack_top]->name = (char *)t;
            travel_stack[stack_top]->next = NULL;
            travel_stack[stack_top]->sub = NULL;
            travel_stack[stack_top]->property = NULL;
            if(stack_top < 1){
                if(!fdt_root_node){
                    fdt_root_node = travel_stack[stack_top];
                    fdt_root_node->parent = NULL;
                }else{
                    errorf("fdt level fault");
                    goto end_travel;
                }
            }else{
                add_sub_node(travel_stack[stack_top - 1], travel_stack[stack_top]);
            }
            // ident(stack_top);
            stack_top++;
            // printf("%s{\n", (char *)t);
            t = ALLIGN4((uint64)t + strlen(t) + 1);
            break;
        case FDT_END_NODE:
            stack_top--;
            // ident(stack_top);
            // printf("}\n");
            t++;
            break;
        case FDT_PROP:
            t++;
            fdt_property *p = alloc_property();
            p->len = bltrans_32(((fdt_struct_property *)t)->len);
            p->name = fdt_strings + bltrans_32(((fdt_struct_property *)t)->nameoff);
            // ident(stack_top);
            // printf("%s:%d\n", p->name, p->len);
            p->next = NULL;
            t += 2;
            p->value = t;
            add_property(travel_stack[stack_top - 1], p);
            // printf("t: %p\n", t, p->len);
            t = (uint64)t + ALLIGN4(p->len);
            // printf("t: %p\n", t);
            break;
        case FDT_END:
            goto end_travel;
        case FDT_NOP:
            // ident(stack_top);
            // printf("nop\n");
        default:
            t++;
        }
    }

    end_travel:
    infof("travel ended at: %p", t);
    kfree(travel_stack);
}

void fdt_node_print(fdt_node *node){
    static int level = 0;
    if(!node){
        return;
    }
    ident(level);
    printf("%s{\n", node->name);
    level++;
    if(node->property){
        fdt_property *pp = node->property;
        ident(level);
        printf("%s: %d\n", pp->name, pp->len);
        while(pp->next){
            pp = pp->next;
            ident(level);
            printf("%s: %d\n", pp->name, pp->len);
        }
    }
    if(node->sub){

        fdt_node *np = node->sub;
        fdt_node_print(np);
        while(np->next){
            np = np->next;
            fdt_node_print(np);
        }
    }
    level--;
    ident(level);
    printf("}\n");
}

int fdt_init(void *addr){
    printbuf(addr, 64, 16);
    fdt_hdr = (fdt_header *)addr;
    if(bltrans_32(fdt_hdr->magic) != FDT_MAGIC){
        errorf("dtb init failed");
        return -1;
    }
    fdt_mem_rsv = addr + bltrans_32(fdt_hdr->off_mem_rsvmap);
    fdt_structs = addr + bltrans_32(fdt_hdr->off_dt_struct);
    fdt_structs_end = fdt_structs + bltrans_32(fdt_hdr->size_dt_struct);
    fdt_strings = addr + bltrans_32(fdt_hdr->off_dt_strings);
    fdt_end = addr + bltrans_32(fdt_hdr->totalsize);

    for(int i = 0; i < FDT_PROPERTY_PAGE_NUM; i++){
        fdt_property_pool[i] = kalloc();
    }
    next_property = 0;

    for(int i = 0; i < FDT_NODE_PAGE_NUM; i++){
        fdt_node_pool[i] = kalloc();
    }
    next_node = 0;

    fdt_root_node = NULL;

    fdt_structs_travel();

    fdt_node_print(fdt_root_node);

    return 0;
}

void fdt_hdr_print(){
    printf("fdt start at 0x%x:\n", fdt_hdr);
    printf("\tmagic: %x\n", bltrans_32(fdt_hdr->magic));
    printf("\ttotalsize: 0x%x\n", bltrans_32(fdt_hdr->totalsize));
