fdt_property *get_property(fdt_node *node, const char *name){
    if(!node){
        errorf("node can't be a nullptr");
        return NULL;
    }
    fdt_property *p = node->property;
    while(p){
        if(!strcmp(name, p->name)){
            return p;
        }
        p = p->next;
    }
    infof("property %s not found", name);
    return NULL;
}

fdt_node *get_node(const char *path){
    if(!strlen(path)){
        errorf("path is null");
        return NULL;
    }
    if(path[0] != '/'){
        errorf("invalid path %s", path);
        return NULL;
    }
    char buf[strlen(path) + 1];
    safestrcpy(buf, path, strlen(path) + 1);

}

