Elf64_Ehdr ehdr;

static int read_elf_header(struct file *f){
    if(!f){
        return -1;
    }
    fileseek(f, 0, SEEK_SET);
    if(!fileread(0, f, &ehdr, sizeof(ehdr))){
        return -1;
    }
    // infof("magic: %s", ehdr.magic);
    // printbuf(&ehdr, sizeof(ehdr), 64);
    return 0;
}

int elf_loader(struct file *f, struct proc *p){
    if(read_elf_header(f)){
        return -1;
    }
    uint64 va_start = ehdr.entry;
    infof("entry: %p", va_start);
    uint64 va_end = 0;
    infof("ehdr{ type: %d, entry: %p, phoff: %p, shoff: %p, ehsize: %d, phentsize: %d, phnum: %d}", ehdr.type, ehdr.entry, ehdr.phoff, ehdr.shoff, ehdr.ehsize, ehdr.phentsize, ehdr.phnum);
    for(int i = 0; i < ehdr.phnum; i ++){
        Elf64_Phdr ph;
        fileseek(f, ehdr.phoff + i * ehdr.phentsize, SEEK_SET);
        fileread(0, f, &ph, ehdr.phentsize);
        infof("ph{ memsz: %p, filesz: %p, vaddr: %p, offset: %p, type: %d}", ph.memsz, ph.filesz, ph.vaddr, ph.offset, ph.type);
        if(ph.memsz < ph.filesz){
            return -1;
        }
        if(ph.memsz == 0){
            continue;
        }
        if(ph.type == PT_INERP){
            //!暂时不支持连接动态库
            return -1;
        }else if(ph.type == PT_LOAD){
            void *page;
            uint64 t_start = PGROUNDDOWN(ph.vaddr);
            infof("tstart: %p", t_start);
            uint64 t_end = PGROUNDUP(ph.vaddr + ph.memsz);
            infof("tend: %p", t_end);
            uint64 readed = 0;
            int offset = ph.vaddr % PGSIZE;
            int j = 0;
            fileseek(f, ph.offset, SEEK_SET);
            int perm = PTE_U;
            if(ph.flags & PF_R){
                perm |= PTE_R;
            }
            if(ph.flags & PF_W){
                perm |= PTE_W;
            }
            if(ph.flags & PF_X){
                perm |= PTE_X;
            }
            while(t_start + j * PGSIZE < t_end){
                page = kalloc();
                if(readed < ph.memsz){
                    // if(offset){
                    //     memset(page, 0, offset);
                    // }
                    readed += fileread(0, f, page + offset, MIN((PGSIZE - offset), (ph.memsz - readed)));
                    offset = 0;
                }else if(!offset){
                    memset(page, 0, PGSIZE);
                }
                mappages(p->pagetable, t_start + j * PGSIZE, PGSIZE, page, perm);
                j++;
            }
            va_end = t_end;
        }
    }
    p->max_page = va_end / PGSIZE;
    // infof("stack base: %p", p->ustack_base);
	// alloc main thread
	if (allocthread(p, va_start, 1) != 0) {
		panic("proc %d alloc main thread failed!", p->pid);
	}
	// infof("elf loader finished");
	return 0;
}

#include <lib/binloader.h>
#include <lib/defs.h>
#include <fs/file.h>

int bin_loader(struct file *f, struct proc *p)
{
	if(!f){
		errorf("cannot load an empty file");
		return -1;
	}
	void *page;
	uint64 length = f->size;
	uint64 va_start = BASE_ADDRESS;
	uint64 va_end = PGROUNDUP(BASE_ADDRESS + length);
	for (uint64 va = va_start, off = 0; va < va_end;
	     va += PGSIZE, off += PGSIZE) {
		page = kalloc();
		if (page == 0) {
			panic("...");
		}
		// readi_fat32(ip, 0, (uint64)page, off, PGSIZE);
		fileseek(f, off, SEEK_SET);
		fileread(0, f, page, PGSIZE);
		if (off + PGSIZE > length) {
			memset(page + (length - off), 0,
			       PGSIZE - (length - off));
		}
		if (mappages(p->pagetable, va, PGSIZE, (uint64)page,
			     PTE_U | PTE_R | PTE_W | PTE_X) != 0)
			panic("...");
	}

	p->max_page = va_end / PGSIZE;

	// alloc main thread
	if (allocthread(p, va_start, 1) != 0) {
		panic("proc %d alloc main thread failed!", p->pid);
	}
	debugf("bin loader finished");
	return 0;
}

